func TestQT3_fn_analyze_string(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "analyzeString-001", XPath: "analyze-string(\"\", \"abc\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-002", XPath: "analyze-string((), \"abc\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-002a", XPath: "count(analyze-string((), \"abc\"))", Assertions: []qt3Assertion{qt3AssertEq("1")}},
		{Name: "analyzeString-003", XPath: "analyze-string(\"banana\", \"a\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-004", XPath: "analyze-string(\"banana\", \"custard\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-005", XPath: "analyze-string(\"banana\", \".+\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-006", XPath: "analyze-string(\"banana\", \"an\")", Assertions: []qt3Assertion{qt3AnyOf(qt3CheckSkip())}},
		{Name: "analyzeString-007", XPath: "analyze-string(\"banana\", \"a(n)\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-008", XPath: "analyze-string(\"banana\", \"(a(n?))\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-009", XPath: "analyze-string(\"how now brown cow\", \"(how)|(now)|(brown)|(cow)\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-010", XPath: "analyze-string(\"how now brown cow\", \"(HOW)|(NOW)|(BROWN)|(COW)\", \"i\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-011", XPath: `analyze-string("how now brown cow", " (HOW) | (NOW) 
| (BROWN) | (COW) ", "ix")`, Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-012", XPath: "analyze-string(\"how now brown cow\", \"(.*?ow\\s+)+\", \"\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-013", XPath: `let $in := 
"Mary had a little lamb,
it's fleece was black as soot,
and everywhere that Mary went,
it put its sooty foot."
            return analyze-string($in, "Mary.*foot", "s")`, Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-014", XPath: `let $in := 
"Mary had a little lamb,
it's fleece was black as soot,
and everywhere that Mary went,
it put its sooty foot."
            return analyze-string($in, ".+", "")`, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckSkip())}},
		{Name: "analyzeString-015", XPath: `let $in := 
"Mary had a little lamb,
it's fleece was black as soot,
and everywhere that Mary went,
it put its sooty foot."
            return analyze-string($in, "^.+$", "m")`, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckSkip())}},
		{Name: "analyzeString-016", XPath: `let $in := 
"Mary had a little lamb,
it's fleece was black as soot,
and everywhere that Mary went,
it put its sooty foot."
            return analyze-string($in, "^.+$", "")`, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckSkip())}},
		{Name: "analyzeString-017", XPath: "analyze-string(\"banana\", \"(b)(x?)\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-017a", XPath: "analyze-string(\"banana\", \"(b(x?))\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-018", XPath: "analyze-string(\"banana\", \"(?:b(an)*a)\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-019", XPath: "analyze-string(\"((banana))\", \"(banana)\", \"q\")", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "analyzeString-020", XPath: `let $result := analyze-string("banana", "(b)(anana)") 
        return ($result//@nr)[1] instance of attribute(nr, xs:positiveInteger)`, Skip: "requires XML Schema support", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "analyzeString-021", XPath: "let $result := analyze-string(\"banana\", \"(b)(anana)\") return $result instance of element(*, xs:untyped)", Skip: "requires XML Schema support", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "analyzeString-022", XPath: "let $result := analyze-string(\"banana\", \"(b)(anana)\") return string($result)", Assertions: []qt3Assertion{qt3AssertStringValue("banana")}},
		{Name: "analyzeString-023", XPath: "let $result := analyze-string(\"banana\", \"(b)(anana)\") return string($result/fn:match[1])", Assertions: []qt3Assertion{qt3AssertStringValue("banana")}},
		{Name: "analyzeString-901", XPath: "analyze-string(\"abc\", \")-(\")", ExpectError: true},
		{Name: "analyzeString-902", XPath: "analyze-string(\"abc\", \"abc\", \"w\")", ExpectError: true},
		{Name: "analyzeString-903", XPath: "analyze-string(\"abc\", \"a|b|c?\")", ExpectError: true},
	})
}

func TestQT3_fn_apply(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-apply-01", XPath: "apply(abs#1, [-2])", Assertions: []qt3Assertion{qt3AssertEq("2")}},
		{Name: "fn-apply-02", XPath: "apply(true#0, array {})", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-apply-03", XPath: "apply(string-join#1, [reverse(1 to 5) ! string()])", Assertions: []qt3Assertion{qt3AssertEq("\"54321\"")}},
		{Name: "fn-apply-04", XPath: `let $func := function($a,$b,$c) { $a + $b + $c }
           , $args := [ 1, 2, 3 ]
         return apply($func, $args)`, Assertions: []qt3Assertion{qt3AssertEq("6")}},
		{Name: "fn-apply-06", XPath: "apply(substring('flower', ?, ?), [ 3, 2 ])", Assertions: []qt3Assertion{qt3AssertEq("\"ow\"")}},
		{Name: "fn-apply-07", XPath: `let $f := function-lookup(xs:QName('fn:count'), 1)
         return apply($f, [ ('one', 'two') ])`, Assertions: []qt3Assertion{qt3AssertEq("2")}},
		{Name: "fn-apply-08", XPath: `for $a in 2 to 3
         return
         let $f := function-lookup(xs:QName('fn:concat'), $a)
         return apply($f, array { 1 to $a })`, Assertions: []qt3Assertion{qt3AssertDeepEq("\"12\", \"123\"")}},
		{Name: "fn-apply-09", XPath: `for $name in (true#0, count#1, empty#1, concat#2) 
         return
         let $arity := function-arity($name)
           , $args := array { (1 to $arity) ! 'X' }
         return apply($name, $args)`, Assertions: []qt3Assertion{qt3AssertDeepEq("true(), 1, false(), \"XX\"")}},
		{Name: "fn-apply-10", XPath: `for $f in (
           function($a) { $a },
           function($a, $b) { $a + $b },
           function($a, $b, $c) { $a + $b + $c }
         )
         return apply($f, array { 1 to function-arity($f) })`, Assertions: []qt3Assertion{qt3AssertDeepEq("1, 3, 6")}},
		{Name: "fn-apply-11", XPath: "data#1 => fn:apply([ [ 1 to 3 ] ])", Assertions: []qt3Assertion{qt3AssertDeepEq("1, 2, 3")}},
		{Name: "fn-apply-12", XPath: "apply(false#0, [0])", ExpectError: true},
		{Name: "fn-apply-13", XPath: "apply(string-length#1, [ ('a','b') ])", ExpectError: true},
		{Name: "fn-apply-16", XPath: "apply(if (current-date() lt xs:date('1900-01-01')) then abs#1 else round#1, [-2])", Assertions: []qt3Assertion{qt3AssertEq("-2")}},
		{Name: "fn-apply-17", XPath: "() => apply([])", ExpectError: true},
	})
}

func TestQT3_fn_available_environment_variables(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-available-environment-variables-001", XPath: "fn:exists(fn:available-environment-variables#0)", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-002", XPath: `not(fn:empty(fn:function-lookup(
	  fn:QName('http://www.w3.org/2005/xpath-functions',
	  'available-environment-variables'), 0)))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-003", XPath: "fn:available-environment-variables#1", ExpectError: true},
		{Name: "fn-available-environment-variables-004", XPath: "fn:available-environment-variables#2", ExpectError: true},
		{Name: "fn-available-environment-variables-005", XPath: `let $all := fn:available-environment-variables()
	  return empty($all) or ($all[1] ne "")`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-006", XPath: `(for $e in fn:available-environment-variables()
	   return fn:environment-variable($e) instance of xs:string) = (false())`, Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-available-environment-variables-007", XPath: `let $all := fn:available-environment-variables(), 
	      $n := count(fn:available-environment-variables())
	  return
	      count(
		  for $e in $all return fn:environment-variable($e)
	      ) eq $n`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-008", XPath: `let $all := fn:available-environment-variables()
	  return count($all) eq count(distinct-values($all))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-010", XPath: `let $all := fn:available-environment-variables()
	  return if (fn:empty($all)) then true()
	  else fn:empty(fn:environment-variable(fn:string-join($all)))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-available-environment-variables-011", XPath: `let $all := fn:available-environment-variables()
	  return if (fn:empty($all)) then true()
	  else if ($all = "QTTEST")
	  then fn:environment-variable("QTTEST") eq "42"
	  else false()`, Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

