func TestQT3_fn_contains_token(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-contains-token-09", XPath: "contains-token(\"\", \"\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-10", XPath: "contains-token((), \"\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-11", XPath: "contains-token(\"   \", \"   \")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-12", XPath: "contains-token(codepoints-to-string((9, 10, 13, 32, 13, 10, 9)), \"\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-13", XPath: "contains-token(\"abc\", \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-14", XPath: "contains-token(\" abc \", \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-15", XPath: "contains-token(codepoints-to-string((9, 10, 97, 98, 99, 13, 32)), \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-16", XPath: "contains-token(\"abc def\", \"def\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-17", XPath: "contains-token(codepoints-to-string((97, 98, 99, 13, 32, 10, 100, 101, 102)), \"def\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-18", XPath: "contains-token(codepoints-to-string((9, 9, 97, 98, 99, 13, 32, 10, 100, 101, 102, 10, 10)), \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-19", XPath: "contains-token(\" the quick brown fox jumped over the lazy dog \", 'fox')", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-20", XPath: "contains-token(codepoints-to-string((97, 98, 99, 12, 100, 101, 102)), \"def\")", Skip: "requires XML 1.1", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-21", XPath: "contains-token(codepoints-to-string((97, 98, 99, 160, 100, 101, 102)), \"abc\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-22", XPath: "(contains-token#2, starts-with#2, ends-with#2)!.(\"abc def\", \"def\")", Assertions: []qt3Assertion{qt3AssertDeepEq("true(), false(), true()")}},
		{Name: "fn-contains-token-39", XPath: "contains-token(\"\", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-40", XPath: "contains-token((), \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-41", XPath: "contains-token(\"   \", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-42", XPath: "contains-token(codepoints-to-string((9, 10, 13, 32, 13, 10, 9)), \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-43", XPath: "contains-token(\"abc\", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-44", XPath: "contains-token(\" abc \", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-45", XPath: "contains-token(codepoints-to-string((9, 10, 97, 98, 99, 13, 32)), \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-46", XPath: "contains-token(\"abc def\", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-47", XPath: "contains-token(codepoints-to-string((97, 98, 99, 13, 32, 10, 100, 101, 102)), \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-48", XPath: "contains-token(codepoints-to-string((9, 9, 97, 98, 99, 13, 32, 10, 100, 101, 102, 10, 10)), \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-49", XPath: "contains-token(\" the quick brown fox jumped over the lazy dog \", 'zz')", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-50", XPath: "contains-token(codepoints-to-string((97, 98, 99, 12, 100, 101, 102)), \"abc\")", Skip: "requires XML 1.1", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-51", XPath: "contains-token(codepoints-to-string((97, 98, 99, 160, 100, 101, 102)), \"abc\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-52", XPath: "(contains-token#2, substring-before#2, substring-after#2)[1](\"abc def\", \"zz\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-60", XPath: "contains-token((\"abc\", \"def\"), \"\")", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-61", XPath: "contains-token((\"abc\", \"def\"), \" abc  \")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-62", XPath: "contains-token((\"abc\", \"def\"), codepoints-to-string((9, 10, 13, 97, 98, 99, 32, 13, 10, 9)))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-63", XPath: "contains-token((\"abc def\", \"ghi\"), \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-64", XPath: "contains-token((\" abc def \", \"ghi\"), \"def\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-65", XPath: "contains-token(codepoints-to-string((9, 10, 97, 98, 99, 13, 32)), \"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-70", XPath: "contains-token(\"the quick brown fox\", \"Fox\", \"http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive\")", DefaultCollation: "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-71", XPath: "contains-token(\"the quick brown fox\", \" QUICK \", \"http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive\")", DefaultCollation: "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-contains-token-72", XPath: "contains-token(\"the quick brown fox\", \"quiçk\", \"http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive\")", DefaultCollation: "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-contains-token-73", XPath: "contains-token(\"\", \"quick\", \"http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive\")", DefaultCollation: "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", Assertions: []qt3Assertion{qt3AssertFalse()}},
	})
}

