func TestQT3_fn_encode_for_uri(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-encode-for-uri1args-1", XPath: "fn:encode-for-uri (\"http://www.example.com/00/Weather/CA/Los%20Angeles#ocean\")", Assertions: []qt3Assertion{qt3AssertStringValue("http%3A%2F%2Fwww.example.com%2F00%2FWeather%2FCA%2FLos%2520Angeles%23ocean")}},
		{Name: "fn-encode-for-uri1args-2", XPath: "encode-for-uri(\"~bébé\")", Assertions: []qt3Assertion{qt3AssertStringValue("~b%C3%A9b%C3%A9")}},
		{Name: "fn-encode-for-uri1args-3", XPath: "encode-for-uri(\"100% organic\")", Assertions: []qt3Assertion{qt3AssertStringValue("100%25%20organic")}},
		{Name: "fn-encode-for-uri1args-4", XPath: "encode-for-uri('')", Assertions: []qt3Assertion{qt3AssertStringValue("")}},
		{Name: "fn-encode-for-uri1args-5", XPath: "encode-for-uri(())", Assertions: []qt3Assertion{qt3AssertStringValue("")}},
		{Name: "fn-encode-for-uri1args-6", XPath: "encode-for-uri(12)", ExpectError: true},
		{Name: "fn-encode-for-uri1args-7", XPath: "encode-for-uri('',())", ExpectError: true},
		{Name: "fn-encode-for-uri-1", XPath: "(fn:encode-for-uri(\"example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("example")}},
		{Name: "fn-encode-for-uri-2", XPath: "(fn:encode-for-uri(\"examples#example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%23example")}},
		{Name: "fn-encode-for-uri-3", XPath: "(fn:encode-for-uri(\"examples-example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples-example")}},
		{Name: "fn-encode-for-uri-4", XPath: "(fn:encode-for-uri(\"examples_example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples_example")}},
		{Name: "fn-encode-for-uri-5", XPath: "(fn:encode-for-uri(\"examples.example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples.example")}},
		{Name: "fn-encode-for-uri-6", XPath: "(fn:encode-for-uri(\"examples!example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%21example")}},
		{Name: "fn-encode-for-uri-7", XPath: "(fn:encode-for-uri(\"examples~example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples~example")}},
		{Name: "fn-encode-for-uri-8", XPath: "(fn:encode-for-uri(\"examples*example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%2Aexample")}},
		{Name: "fn-encode-for-uri-9", XPath: "(fn:encode-for-uri(\"examples'example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%27example")}},
		{Name: "fn-encode-for-uri-10", XPath: "(fn:encode-for-uri(\"examples(example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%28example")}},
		{Name: "fn-encode-for-uri-11", XPath: "(fn:encode-for-uri(\"examples)example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%29example")}},
		{Name: "fn-encode-for-uri-12", XPath: "(fn:encode-for-uri(\"examples0123456789example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples0123456789example")}},
		{Name: "fn-encode-for-uri-13", XPath: "(fn:encode-for-uri(\"examples example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%20example")}},
		{Name: "fn-encode-for-uri-14", XPath: "(fn:encode-for-uri(\"examples/example\"))", Assertions: []qt3Assertion{qt3AssertStringValue("examples%2Fexample")}},
		{Name: "fn-encode-for-uri-15", XPath: "(fn:encode-for-uri(\"http:examples\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http%3Aexamples")}},
		{Name: "fn-encode-for-uri-16", XPath: "(fn:encode-for-uri(\"http%20examples\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http%2520examples")}},
		{Name: "K-EncodeURIfunc-1", XPath: "encode-for-uri()", ExpectError: true},
		{Name: "K-EncodeURIfunc-2", XPath: "encode-for-uri(\"http://example.com/\", \"wrong param\")", ExpectError: true},
		{Name: "K-EncodeURIfunc-3", XPath: "encode-for-uri(()) eq \"\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EncodeURIfunc-4", XPath: "concat(\"http://www.example.com/\", encode-for-uri(\"~bébé\")) eq \"http://www.example.com/~b%C3%A9b%C3%A9\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EncodeURIfunc-5", XPath: "concat(\"http://www.example.com/\", encode-for-uri(\"100% organic\")) eq \"http://www.example.com/100%25%20organic\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EncodeURIfunc-6", XPath: "normalize-space(encode-for-uri((\"some string\", current-time())[1] treat as xs:string))", Assertions: []qt3Assertion{qt3AssertStringValue("some%20string")}},
	})
}

