func TestQT3_fn_environment_variable(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "environment-variable-001", XPath: "fn:exists(environment-variable#1)", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "environment-variable-002", XPath: `not(fn:empty(fn:function-lookup(
	  fn:QName('http://www.w3.org/2005/xpath-functions',
	  'environment-variable') , 1)))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "environment-variable-003", XPath: "fn:environment-variables#0", ExpectError: true},
		{Name: "environment-variable-004", XPath: "fn:environment-variables#2", ExpectError: true},
		{Name: "environment-variable-005", XPath: `let $all := fn:available-environment-variables()
	  return empty($all) or ($all = "QTTEST" and fn:environment-variable("QTTEST") eq "42")`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "environment-variable-006", XPath: `let $all := fn:available-environment-variables()
	  return empty($all) or
	      ($all = "QTTEST2"
	       and (fn:environment-variable("QTTEST2") eq "other")
	       and (not("other" eq "42")))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "environment-variable-007", XPath: `let $all := fn:available-environment-variables()
	  return empty($all) or ($all = "QTTESTEMPTY" and fn:environment-variable("QTTESTEMPTY") eq "")`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "environment-variable-008", XPath: "fn:environment-variable()", ExpectError: true},
		{Name: "environment-variable-009", XPath: "fn:environment-variable(1)", ExpectError: true},
		{Name: "environment-variable-010", XPath: "fn:environment-variable(())", ExpectError: true},
		{Name: "environment-variable-011", XPath: "fn:environment-variable(true())", ExpectError: true},
		{Name: "environment-variable-012", XPath: `let $var := string-join(
	  for $i in (1 to (1024 * 1024)) return "x"
	) 
	return empty(fn:environment-variable($var))`, Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

