func TestQT3_fn_escape_html_uri(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-escape-html-uri1args-1", XPath: "escape-html-uri(\"http://www.example.com/00/Weather/CA/Los Angeles#ocean\")", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/00/Weather/CA/Los Angeles#ocean")}},
		{Name: "fn-escape-html-uri1args-2", XPath: "escape-html-uri(\"javascript:if (navigator.browserLanguage == 'fr') window.open('http://www.example.com/~bébé');\")", Assertions: []qt3Assertion{qt3AssertStringValue("javascript:if (navigator.browserLanguage == 'fr') window.open('http://www.example.com/~b%C3%A9b%C3%A9');")}},
		{Name: "fn-escape-html-uri1args-3", XPath: "escape-html-uri('')", Assertions: []qt3Assertion{qt3AssertStringValue("")}},
		{Name: "fn-escape-html-uri1args-4", XPath: "escape-html-uri(())", Assertions: []qt3Assertion{qt3AssertStringValue("")}},
		{Name: "fn-escape-html-uri1args-5", XPath: "escape-html-uri(12)", ExpectError: true},
		{Name: "fn-escape-html-uri1args-6", XPath: "escape-html-uri('',())", ExpectError: true},
		{Name: "fn-escape-html-uri-1", XPath: "fn:escape-html-uri(\"abcdedfghijklmnopqrstuvwxyz\")", Assertions: []qt3Assertion{qt3AssertStringValue("abcdedfghijklmnopqrstuvwxyz")}},
		{Name: "fn-escape-html-uri-2", XPath: "fn:escape-html-uri(\"ABCDEFGHIJKLMNOPQRSTUVWXYZ\")", Assertions: []qt3Assertion{qt3AssertStringValue("ABCDEFGHIJKLMNOPQRSTUVWXYZ")}},
		{Name: "fn-escape-html-uri-3", XPath: "fn:escape-html-uri(\"a0123456789\")", Assertions: []qt3Assertion{qt3AssertStringValue("a0123456789")}},
		{Name: "fn-escape-html-uri-4", XPath: "fn:escape-html-uri(\"example example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example example")}},
		{Name: "fn-escape-html-uri-5", XPath: "fn:escape-html-uri(\"example!example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example!example")}},
		{Name: "fn-escape-html-uri-6", XPath: "fn:escape-html-uri(\"example#example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example#example")}},
		{Name: "fn-escape-html-uri-7", XPath: "fn:escape-html-uri(\"example$example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example$example")}},
		{Name: "fn-escape-html-uri-8", XPath: "fn:escape-html-uri(\"example'example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example'example")}},
		{Name: "fn-escape-html-uri-9", XPath: "fn:escape-html-uri(\"example(example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example(example")}},
		{Name: "fn-escape-html-uri-10", XPath: "fn:escape-html-uri(\"example)example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example)example")}},
		{Name: "fn-escape-html-uri-11", XPath: "fn:escape-html-uri(\"example*example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example*example")}},
		{Name: "fn-escape-html-uri-12", XPath: "fn:escape-html-uri(\"example+example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example+example")}},
		{Name: "fn-escape-html-uri-13", XPath: "fn:escape-html-uri(\"example,example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example,example")}},
		{Name: "fn-escape-html-uri-14", XPath: "fn:escape-html-uri(\"example-example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example-example")}},
		{Name: "fn-escape-html-uri-15", XPath: "fn:escape-html-uri(\"example.example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example.example")}},
		{Name: "fn-escape-html-uri-16", XPath: "fn:escape-html-uri(\"example/example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example/example")}},
		{Name: "fn-escape-html-uri-17", XPath: "fn:escape-html-uri(\"example;example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example;example")}},
		{Name: "fn-escape-html-uri-18", XPath: "fn:escape-html-uri(\"example:example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example:example")}},
		{Name: "fn-escape-html-uri-19", XPath: "fn:escape-html-uri(\"example@example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example@example")}},
		{Name: "fn-escape-html-uri-20", XPath: "fn:escape-html-uri(\"exampleé€example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example%C3%A9%E2%82%ACexample")}},
		{Name: "fn-escape-html-uri-21", XPath: "fn:escape-html-uri(\"example€example\")", Assertions: []qt3Assertion{qt3AssertStringValue("example%E2%82%ACexample")}},
		{Name: "K-EscapeHTMLURIFunc-1", XPath: "escape-html-uri()", ExpectError: true},
		{Name: "K-EscapeHTMLURIFunc-2", XPath: "escape-html-uri(\"http://example.com/\", \"wrong param\")", ExpectError: true},
		{Name: "K-EscapeHTMLURIFunc-3", XPath: "escape-html-uri(()) eq \"\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EscapeHTMLURIFunc-4", XPath: "escape-html-uri(\"http://www.example.com/00/Weather/CA/Los Angeles#ocean\") eq \"http://www.example.com/00/Weather/CA/Los Angeles#ocean\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EscapeHTMLURIFunc-5", XPath: "escape-html-uri(\"javascript:if (navigator.browserLanguage == 'fr') window.open('http://www.example.com/~bébé');\") eq \"javascript:if (navigator.browserLanguage == 'fr') window.open('http://www.example.com/~b%C3%A9b%C3%A9');\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EscapeHTMLURIFunc-6", XPath: "normalize-space(iri-to-uri((\"example.com\", current-time())[1] treat as xs:string))", Assertions: []qt3Assertion{qt3AssertStringValue("example.com")}},
		{Name: "cbcl-escape-html-uri-001", XPath: "fn:escape-html-uri(codepoints-to-string((9, 65, 128)))", Assertions: []qt3Assertion{qt3AssertStringValue("%09A%C2%80")}},
	})
}

