func TestQT3_fn_prefix_from_QName(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-prefix-from-qname-1", XPath: "fn:prefix-from-QName(\"arg1\",\"arg2\")", ExpectError: true},
		{Name: "fn-prefix-from-qname-2", XPath: "fn:prefix-from-QName(xs:integer(1))", ExpectError: true},
		{Name: "fn-prefix-from-qname-3", XPath: "fn:count(fn:prefix-from-QName(xs:QName(\"name\")))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-prefix-from-qname-4", XPath: "fn:string-length(xs:string(fn:prefix-from-QName(xs:QName(\"name\"))))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-prefix-from-qname-5", XPath: "xs:string(fn:prefix-from-QName(xs:QName(\"foo:name\")))", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo")}},
		{Name: "fn-prefix-from-qname-6", XPath: "fn:string(fn:prefix-from-QName(xs:QName(\"foo:name\")))", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo")}},
		{Name: "fn-prefix-from-qname-7", XPath: "fn:count(fn:prefix-from-QName(()))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-prefix-from-qname-8", XPath: "fn:prefix-from-QName(xs:QName(\"foo:bar\"))", ExpectError: true},
		{Name: "fn-prefix-from-qname-9", XPath: "fn:upper-case(fn:prefix-from-QName(xs:QName(\"foo:bar\")))", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("FOO")}},
		{Name: "fn-prefix-from-qname-10", XPath: "fn:lower-case(fn:prefix-from-QName(xs:QName(\"FOO:bar\")))", Namespaces: map[string]string{"FOO": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo")}},
		{Name: "fn-prefix-from-qname-11", XPath: "fn:concat(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\":bar\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo:bar")}},
		{Name: "fn-prefix-from-qname-12", XPath: "fn:substring-before(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\"oo\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("f")}},
		{Name: "fn-prefix-from-qname-13", XPath: "fn:substring-after(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\"f\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("oo")}},
		{Name: "fn-prefix-from-qname-14", XPath: "fn:string-length(fn:prefix-from-QName(xs:QName(\"foo:bar\")))", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("3")}},
		{Name: "fn-prefix-from-qname-15", XPath: "fn:substring(fn:prefix-from-QName(xs:QName(\"foo:bar\")),2)", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("oo")}},
		{Name: "fn-prefix-from-qname-16", XPath: "fn:string-join((fn:prefix-from-QName(xs:QName(\"foo:bar\")),\":bar\"),\"\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo:bar")}},
		{Name: "fn-prefix-from-qname-17", XPath: "fn:starts-with(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\"f\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-prefix-from-qname-18", XPath: "fn:ends-with(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\"f\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-prefix-from-qname-19", XPath: "fn:contains(fn:prefix-from-QName(xs:QName(\"foo:bar\")),\"f\")", Namespaces: map[string]string{"foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-prefix-from-qname-20", XPath: "fn:prefix-from-QName(xs:QName(\"foo:bar\"))", Namespaces: map[string]string{"FOO": "http://example.org", "foo": "http://example.org"}, Assertions: []qt3Assertion{qt3AssertStringValue("foo")}},
		{Name: "fn-prefix-from-qname-21", XPath: "fn:prefix-from-QName(node-name(/*))", DocPath: "docs/atomic.xml", NeedsHTTP: true, ResourceMap: map[string]string{"http://www.w3.org/fots/docs/atomic.xml": "docs/atomic.xml"}, Namespaces: map[string]string{"atomic": "http://www.w3.org/XQueryTest"}, Skip: "requires schema-validated source", Assertions: []qt3Assertion{qt3AssertStringValue("atomic"), qt3AssertType("xs:NCName")}},
		{Name: "fn-prefix-from-qname-22", XPath: "fn:prefix-from-QName(node-name((//@*)[1]))", DocPath: "docs/atomic.xml", NeedsHTTP: true, ResourceMap: map[string]string{"http://www.w3.org/fots/docs/atomic.xml": "docs/atomic.xml"}, Namespaces: map[string]string{"atomic": "http://www.w3.org/XQueryTest"}, Skip: "requires schema-validated source", Assertions: []qt3Assertion{qt3AssertStringValue("atomic"), qt3AssertType("xs:NCName")}},
		{Name: "fn-prefix-from-qname-23", XPath: "fn:prefix-from-QName(node-name(/*))", DocPath: "docs/works-mod.xml", Assertions: []qt3Assertion{qt3AssertEmpty()}},
		{Name: "K-PrefixFromQName-1", XPath: "prefix-from-QName()", ExpectError: true},
		{Name: "K-PrefixFromQName-2", XPath: "prefix-from-QName(1, 2)", ExpectError: true},
		{Name: "K-PrefixFromQName-3", XPath: "empty(prefix-from-QName( () ))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-PrefixFromQName-4", XPath: "prefix-from-QName( QName(\"example.com/\", \"pre:lname\")) eq \"pre\"", Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

