func TestQT3_fn_resolve_uri(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-resolve-uri-1", XPath: "fn:count(fn:resolve-uri((),\"BaseValue\"))", Assertions: []qt3Assertion{qt3AssertEq("0")}},
		{Name: "fn-resolve-uri-3", XPath: "fn:resolve-uri(\":\",\"http://www.example.com/\")", ExpectError: true},
		{Name: "fn-resolve-uri-4", XPath: "fn:resolve-uri(\"examples\",\"http:%%\")", ExpectError: true},
		{Name: "fn-resolve-uri-5", XPath: "fn:string(fn:resolve-uri(\"http://www.examples.com\",\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com")}},
		{Name: "fn-resolve-uri-6", XPath: "fn:string(fn:resolve-uri(\"examples\",\"http://www.examples.com/\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/examples")}},
		{Name: "fn-resolve-uri-7", XPath: "fn:string(fn:resolve-uri(\"examples\",xs:string(\"http://www.examples.com/\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/examples")}},
		{Name: "fn-resolve-uri-8", XPath: "fn:string(fn:resolve-uri(fn:string(\"examples\"),fn:string(\"http://www.examples.com/\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/examples")}},
		{Name: "fn-resolve-uri-9", XPath: "fn:string(fn:resolve-uri(fn:upper-case(\"examples\"),fn:upper-case(\"http://www.examples.com/\")))", Assertions: []qt3Assertion{qt3AnyOf(qt3CheckStringValue("HTTP://WWW.EXAMPLES.COM/EXAMPLES"), qt3CheckStringValue("http://www.examples.com/EXAMPLES"))}},
		{Name: "fn-resolve-uri-10", XPath: "fn:string(fn:resolve-uri(fn:lower-case(\"EXAMPLES\"),fn:lower-case(\"HTTP://www.examples.com/\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/examples")}},
		{Name: "fn-resolve-uri-11", XPath: "fn:string(fn:resolve-uri(\"examples\",fn:substring(\"1234http://www.examples.com/\",5)))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/examples")}},
		{Name: "fn-resolve-uri-12", XPath: "fn:string(fn:resolve-uri(\"examples\",fn:string-join(('http://www.example','.com/'),'')))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/examples")}},
		{Name: "fn-resolve-uri-13", XPath: "fn:string(fn:resolve-uri(\"examples\",fn:concat(\"http://www.example\",\".com/\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/examples")}},
		{Name: "fn-resolve-uri-14", XPath: "fn:string(fn:resolve-uri(\"examples\",fn:substring-before(\"http://www.example.com/123\",\"123\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/examples")}},
		{Name: "fn-resolve-uri-15", XPath: "fn:string(fn:resolve-uri(\"examples\",fn:substring-after(\"123http://www.example.com/\",\"123\")))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/examples")}},
		{Name: "fn-resolve-uri-16", XPath: "fn:string(fn:resolve-uri(fn:string(\"http://www.examples.com/\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com/")}},
		{Name: "fn-resolve-uri-17", XPath: "fn:string(fn:resolve-uri(fn:upper-case(\"http://www.examples.com\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("HTTP://WWW.EXAMPLES.COM")}},
		{Name: "fn-resolve-uri-18", XPath: "fn:string(fn:resolve-uri(fn:lower-case(\"http://www.examples.com\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com")}},
		{Name: "fn-resolve-uri-19", XPath: "fn:string(fn:resolve-uri(fn:substring(\"123http://www.examples.com\",4),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com")}},
		{Name: "fn-resolve-uri-20", XPath: "fn:string(fn:resolve-uri(fn:string-join((\"http://www.examples\",\".com\"),''),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com")}},
		{Name: "fn-resolve-uri-21", XPath: "fn:string(fn:resolve-uri(fn:concat(\"http://www.examples\",\".com\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.examples.com")}},
		{Name: "fn-resolve-uri-22", XPath: "fn:string(fn:resolve-uri(fn:substring-before(\"http://www.example.com123\",\"123\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com")}},
		{Name: "fn-resolve-uri-23", XPath: "fn:string(fn:resolve-uri(fn:substring-after(\"123http://www.example.com\",\"123\"),\"\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com")}},
		{Name: "fn-resolve-uri-24", XPath: "fn:string(fn:resolve-uri(\"a.html\",\"b.html\"))", ExpectError: true},
		{Name: "fn-resolve-uri-25", XPath: "string(resolve-uri(\"http://www.example.com/a.html\",\"b.html\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/a.html")}},
		{Name: "fn-resolve-uri-26", XPath: "resolve-uri(\"b.html\", \"http://www.example.com/a.html#fragment\")", ExpectError: true},
		{Name: "fn-resolve-uri-27", XPath: "string(resolve-uri(\"b.html\", \"http://www.example.com/a.html?foo=bar\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/b.html")}},
		{Name: "fn-resolve-uri-29", XPath: "string(resolve-uri(\"urn:isbn:01234567890X\", \"http://www.example.com/\"))", Assertions: []qt3Assertion{qt3AssertStringValue("urn:isbn:01234567890X")}},
		{Name: "fn-resolve-uri-30", XPath: `resolve-uri(codepoints-to-string(231)||".html", "http://www.example.com/"||codepoints-to-string(224)||".html")
         = ("http://www.example.com/"||codepoints-to-string(231)||".html")`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-resolve-uri-31", XPath: `resolve-uri("%C3%A0.html", "http://www.example.com/%C3%A7.html")
         = "http://www.example.com/%C3%A0.html"`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-resolve-uri-32", XPath: "resolve-uri(\"this doc.html\", \"http://www.example.com/that doc.html\")", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckStringValue("http://www.example.com/this doc.html"))}},
		{Name: "fn-resolve-uri-33", XPath: "resolve-uri(\"http://www.example.com/books.xml\", \"urn:doi:234567\")", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckStringValue("http://www.example.com/books.xml"))}},
		{Name: "K-ResolveURIFunc-1", XPath: "resolve-uri()", ExpectError: true},
		{Name: "K-ResolveURIFunc-2", XPath: "resolve-uri(\"http://www.example.com/\", \"relative/uri.ext\", \"wrong param\")", ExpectError: true},
		{Name: "K-ResolveURIFunc-3", XPath: "resolve-uri(\"relative/uri.ext\", \"http://www.example.com/\") eq xs:anyURI(\"http://www.example.com/relative/uri.ext\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-ResolveURIFunc-4", XPath: "resolve-uri(\"\", \"http://www.example.com/\") eq xs:anyURI(\"http://www.example.com/\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-ResolveURIFunc-5", XPath: "empty(resolve-uri((), \"http://www.example.com/\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-ResolveURIFunc-6", XPath: "resolve-uri(\"http://www.example.com/absolute\", \"http://www.example.com/\") eq xs:anyURI(\"http://www.example.com/absolute\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "cbcl-fn-resolve-uri-001", XPath: "boolean(resolve-uri(string-join(for $x in 1 to 10 return \"blah\",\"z\"),\"http://localhost/\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

