func TestQT3_fn_root(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-root-1", XPath: "fn:root()", ExpectError: true},
		{Name: "fn-root-2", XPath: "(1 to 100)[fn:root()]", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckCount(100))}},
		{Name: "fn-root-2a", XPath: "1 = (1, fn:root(1[. = 1]))", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckTrue())}},
		{Name: "fn-root-2b", XPath: "exists(1 = fn:root(1[. = 1]))", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckTrue())}},
		{Name: "fn-root-3", XPath: "fn:count(fn:root(()))", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckEq("0"))}},
		{Name: "fn-root-14", XPath: "fn:root(fn:exactly-one(/langs[1]/para[1]))", DocPath: "fn/lang/lang.xml", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "fn-root-15", XPath: "fn:root(/langs[1]/para[1]/@xml:lang)", DocPath: "fn/lang/lang.xml", Assertions: []qt3Assertion{qt3AssertSkip()}},
		{Name: "fn-root-24", XPath: "fn:root(.)", ExpectError: true},
		{Name: "K-NodeRootFunc-1", XPath: "Root(2)", ExpectError: true},
		{Name: "K-NodeRootFunc-2", XPath: "(1, 2, 3)[root()[generate-id() != '***']]", ExpectError: true},
		{Name: "K-NodeRootFunc-3", XPath: "root(2)", ExpectError: true},
		{Name: "K-NodeRootFunc-4", XPath: "empty(root(()))", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckTrue())}},
	})
}

