func TestQT3_fn_seconds_from_dateTime(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-seconds-from-dateTime1args-1", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T00:00:00Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-seconds-from-dateTime1args-2", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1996-04-07T01:40:52Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("52")}},
		{Name: "fn-seconds-from-dateTime1args-3", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"2030-12-31T23:59:59Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("59")}},
		{Name: "fn-seconds-from-dateTime-1", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1999-05-31T13:20:00-05:00\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-seconds-from-dateTime-2", XPath: "fn:avg((fn:seconds-from-dateTime(xs:dateTime(\"1999-05-31T13:30:10Z\")), fn:seconds-from-dateTime(xs:dateTime(\"1999-05-31T13:30:15Z\"))))", Assertions: []qt3Assertion{qt3AssertStringValue("12.5")}},
		{Name: "fn-seconds-from-dateTime-3", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1999-12-31T21:20:20-05:00\")) lt fn:seconds-from-dateTime(xs:dateTime(\"1999-12-31T21:20:20-05:00\"))", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-seconds-from-dateTime-4", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1999-12-31T21:20:20-05:00\")) le fn:seconds-from-dateTime(xs:dateTime(\"1999-12-31T21:20:20-05:00\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-seconds-from-dateTime-5", XPath: "fn:count(fn:seconds-from-dateTime(()))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-seconds-from-dateTime-6", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1999-05-31T20:00:00-05:00\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-seconds-from-dateTime-7", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1999-05-31T23:59:59-05:00\"))", Assertions: []qt3Assertion{qt3AssertStringValue("59")}},
		{Name: "fn-seconds-from-dateTime-8", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T00:00:10Z\")) + fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:00:11Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("21")}},
		{Name: "fn-seconds-from-dateTime-9", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T00:00:10Z\")) - fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:00:00Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("10")}},
		{Name: "fn-seconds-from-dateTime-10", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T02:02:02Z\")) * fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:03:03Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("6")}},
		{Name: "fn-seconds-from-dateTime-11", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T02:10:10Z\")) div fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:05:05Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("2")}},
		{Name: "fn-seconds-from-dateTime-12", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) idiv fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T02:05:05Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("2")}},
		{Name: "fn-seconds-from-dateTime-13", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) mod fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T03:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-seconds-from-dateTime-14", XPath: "+fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("10")}},
		{Name: "fn-seconds-from-dateTime-15", XPath: "-fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("-10")}},
		{Name: "fn-seconds-from-dateTime-16", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) eq fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-seconds-from-dateTime-17", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) ne fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-seconds-from-dateTime-18", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) le fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-seconds-from-dateTime-19", XPath: "fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\")) ge fn:seconds-from-dateTime(xs:dateTime(\"1970-01-01T10:10:10Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-SecondsFromDateTimeFunc-1", XPath: "seconds-from-dateTime()", ExpectError: true},
		{Name: "K-SecondsFromDateTimeFunc-2", XPath: "seconds-from-dateTime((), \"Wrong param\")", ExpectError: true},
		{Name: "K-SecondsFromDateTimeFunc-3", XPath: "empty(seconds-from-dateTime(()))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-SecondsFromDateTimeFunc-4", XPath: "seconds-from-dateTime(()) instance of xs:decimal?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-SecondsFromDateTimeFunc-5", XPath: "seconds-from-dateTime(xs:dateTime(\"2001-02-03T08:23:12.43\")) eq 12.43", Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

