func TestQT3_fn_year_from_date(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "fn-year-from-date1args-1", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1970")}},
		{Name: "fn-year-from-date1args-2", XPath: "fn:year-from-date(xs:date(\"1983-11-17Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1983")}},
		{Name: "fn-year-from-date1args-3", XPath: "fn:year-from-date(xs:date(\"2030-12-31Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("2030")}},
		{Name: "fn-year-from-date-1", XPath: "fn:year-from-date(xs:date(\"1999-05-31Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1999")}},
		{Name: "fn-year-from-date-2", XPath: "fn:year-from-date(xs:date(\"2000-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("2000")}},
		{Name: "fn-year-from-date-3", XPath: "fn:year-from-date(xs:date(\"1999-12-31Z\")) lt fn:year-from-date(xs:date(\"1999-12-31Z\"))", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-year-from-date-4", XPath: "fn:year-from-date(xs:date(\"1999-12-31Z\")) le fn:year-from-date(xs:date(\"1999-12-31Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-year-from-date-5", XPath: "fn:count(fn:year-from-date(()))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-year-from-date-6", XPath: "fn:year-from-date(xs:date(\"0001-05-31Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1")}},
		{Name: "fn-year-from-date-7", XPath: "fn:year-from-date(xs:date(\"-1999-05-31Z\"))", AcceptError: true, Assertions: []qt3Assertion{qt3AnyOf(qt3CheckStringValue("-1999"))}},
		{Name: "fn-year-from-date-8", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) + fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("3940")}},
		{Name: "fn-year-from-date-9", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) - fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-year-from-date-10", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) * fn:year-from-date(xs:date(\"0002-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("3940")}},
		{Name: "fn-year-from-date-11", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) div fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1")}},
		{Name: "fn-year-from-date-12", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) idiv fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1")}},
		{Name: "fn-year-from-date-13", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) mod fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "fn-year-from-date-14", XPath: "+fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("1970")}},
		{Name: "fn-year-from-date-15", XPath: "-fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertStringValue("-1970")}},
		{Name: "fn-year-from-date-16", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) eq fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-year-from-date-17", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) ne fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "fn-year-from-date-18", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) le fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "fn-year-from-date-19", XPath: "fn:year-from-date(xs:date(\"1970-01-01Z\")) ge fn:year-from-date(xs:date(\"1970-01-01Z\"))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-YearFromDateFunc-1", XPath: "year-from-date()", ExpectError: true},
		{Name: "K-YearFromDateFunc-2", XPath: "year-from-date((), \"Wrong param\")", ExpectError: true},
		{Name: "K-YearFromDateFunc-3", XPath: "empty(year-from-date(()))", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-YearFromDateFunc-4", XPath: "year-from-date(()) instance of xs:integer?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-YearFromDateFunc-5", XPath: "year-from-date(xs:date(\"2000-02-03\")) eq 2000", Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

